# Utility module providing helper functions and formatting

def format_number(n: float) -> str:
    return f"Value: {n:.2f}"

def double_value(x: int) -> int:
    return x * 2

class Formatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format(self, value: int) -> str:
        return f"{self.prefix}{value}"

