# Math operations module that depends on utils
from utils import format_number, double_value

def calculate_average(a: int, b: int) -> float:
    total: int = a + b
    return total / 2.0

def scale_and_format(base: int, multiplier: int) -> str:
    scaled: int = base * multiplier
    doubled: int = double_value(scaled)
    return format_number(doubled as float)

class Calculator:
    name: str

    def __init__(self, name: str):
        self.name = name

    def compute(self, x: int, y: int) -> float:
        return calculate_average(x, y) * 2.0

    def describe(self) -> str:
        return f"Calculator: {self.name}"
